//! AUTO-GENERATED by the spec-word-compliance workflow.
//!
//! Area: "Symbol characters and rendered-layout markers (sym, lastRenderedPageBreak)".
//!
//! Each `#[test]` encodes a Word-compliance constraint mined from
//! ECMA-376 / ISO 29500-1 / MS-OI29500. A FAILING assertion means stemma
//! diverges from Word on that constraint — i.e. it encodes a REAL
//! Word-compliance gap, not a flaky/aspirational test. Never weaken an
//! assertion to make it pass; a fail is the finding we are hunting for.
//!
//! Methodology note (consumption vs. save): stemma round-trips UNTOUCHED
//! content byte-verbatim (passthrough archive write). So `reserialize()` of an
//! unedited document reflects stemma's verbatim-preservation contract, NOT
//! Word's render-normalization. Therefore xml* assertions here only target
//! markup that stemma's serializer ACTIVELY generates / restructures, plus the
//! verbatim-preservation contract for opaque inlines (w:sym, lastRenderedPageBreak),
//! and opens-clean validity. Word CONSUMPTION semantics (what the marker
//! contributes to the read text) are asserted on the READ side
//! (read_accepted/read_rejected text).
//!
//! NOTE on xmlRegex expectations: the `regex` crate is not a dev-dependency of
//! `stemma`, so spec `xmlRegex` rules are translated to equivalent `contains` /
//! ordering / occurrence-count checks. Each translation is noted at its site.

use stemma::ExportOptions;
use stemma::api::{Document, validate};

// ─── Prelude / plumbing ─────────────────────────────────────────────────────

/// Build a valid minimal `.docx`. `body_xml` is wrapped in
/// `<w:document …><w:body> … </w:body></w:document>`. `extra_parts` are
/// `(part_name, xml)` pairs (e.g. `("word/styles.xml", "…")`) added to the zip
/// with matching content-type overrides.
fn make_docx(body_xml: &str, extra_parts: &[(&str, &str)]) -> Vec<u8> {
    let document_xml = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<w:document xmlns:w="http://schemas.openxmlformats.org/wordprocessingml/2006/main"><w:body>{body_xml}</w:body></w:document>"#,
    );

    // Content-type overrides for any extra parts. We only support the parts
    // these specs actually use; anything else is a programmer error and we fail
    // fast rather than guessing a content type.
    let mut overrides = String::from(
        r#"<Override PartName="/word/document.xml" ContentType="application/vnd.openxmlformats-officedocument.wordprocessingml.document.main+xml"/>"#,
    );
    for (part_name, _) in extra_parts {
        let ct = match *part_name {
            "word/styles.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.styles+xml"
            }
            "word/numbering.xml" => {
                "application/vnd.openxmlformats-officedocument.wordprocessingml.numbering+xml"
            }
            other => panic!("make_docx: no content-type mapping for extra part {other}"),
        };
        overrides.push_str(&format!(
            r#"<Override PartName="/{part_name}" ContentType="{ct}"/>"#
        ));
    }

    let content_types = format!(
        r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?><Types xmlns="http://schemas.openxmlformats.org/package/2006/content-types"><Default Extension="rels" ContentType="application/vnd.openxmlformats-package.relationships+xml"/><Default Extension="xml" ContentType="application/xml"/>{overrides}</Types>"#
    );
    let rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"><Relationship Id="rId1" Type="http://schemas.openxmlformats.org/officeDocument/2006/relationships/officeDocument" Target="word/document.xml"/></Relationships>"#;
    let doc_rels = r#"<?xml version="1.0" encoding="UTF-8" standalone="yes"?>
<Relationships xmlns="http://schemas.openxmlformats.org/package/2006/relationships"/>"#;

    use std::io::Write;
    use zip::write::FileOptions;
    let mut buf = Vec::new();
    {
        let mut zip = zip::ZipWriter::new(std::io::Cursor::new(&mut buf));
        let opts: FileOptions = FileOptions::default();
        zip.start_file("[Content_Types].xml", opts).unwrap();
        zip.write_all(content_types.as_bytes()).unwrap();
        zip.start_file("_rels/.rels", opts).unwrap();
        zip.write_all(rels.as_bytes()).unwrap();
        zip.start_file("word/_rels/document.xml.rels", opts)
            .unwrap();
        zip.write_all(doc_rels.as_bytes()).unwrap();
        zip.start_file("word/document.xml", opts).unwrap();
        zip.write_all(document_xml.as_bytes()).unwrap();
        for (part_name, xml) in extra_parts {
            zip.start_file(*part_name, opts).unwrap();
            zip.write_all(xml.as_bytes()).unwrap();
        }
        zip.finish().unwrap();
    }
    buf
}

/// Unzip and return `word/document.xml` as a String.
fn document_xml_of(docx: &[u8]) -> String {
    let reader = std::io::Cursor::new(docx);
    let mut zip = zip::ZipArchive::new(reader).expect("open zip");
    let mut file = zip
        .by_name("word/document.xml")
        .expect("word/document.xml present");
    use std::io::Read;
    let mut out = String::new();
    file.read_to_string(&mut out).expect("read document.xml");
    out
}

/// Parse -> serialize(ExportOptions::default()) -> document.xml String.
fn reserialize(bytes: &[u8]) -> String {
    let doc = Document::parse(bytes).expect("parse");
    let out = doc.serialize(&ExportOptions::default()).expect("serialize");
    document_xml_of(&out)
}

/// True iff `validate(bytes)` reports no errors (opens clean), with detail.
fn opens_clean(bytes: &[u8]) -> (bool, String) {
    let report = validate(bytes);
    let detail = report
        .issues
        .iter()
        .map(|i| format!("[{:?}] {}", i.code, i.message))
        .collect::<Vec<_>>()
        .join("; ");
    (report.ok, detail)
}

/// Accept-all reading of the document's plain text.
fn accept_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_accepted()
        .expect("accept-all")
        .to_text()
}

/// Reject-all reading of the document's plain text.
fn reject_text(bytes: &[u8]) -> String {
    Document::parse(bytes)
        .expect("parse")
        .read_rejected()
        .expect("reject-all")
        .to_text()
}

// ─── Tests ──────────────────────────────────────────────────────────────────

#[test]
fn sym_char_and_font_preserved_verbatim_on_roundtrip() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="Courier New" w:hAnsi="Courier New"/></w:rPr><w:t>This is a symbol character:</w:t><w:sym w:font="Wingdings" w:char="F0E8"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:font="Wingdings""#),
        "ECMA-376 §17.3.3.30 / ISO 29500-1 §17.3.3.30: the symbol glyph is pulled from the font named in sym@font; the value must survive serialize unchanged. Expected XML to contain w:font=\"Wingdings\". xml: {xml}"
    );
    assert!(
        xml.contains(r#"w:char="F0E8""#),
        "ECMA-376 §17.3.3.30 / ISO 29500-1 §17.3.3.30: the glyph is the char-attribute code from that font; the exact hex code must survive serialize unchanged. Expected XML to contain w:char=\"F0E8\". xml: {xml}"
    );
    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "ECMA-376 §17.3.3.30: a well-formed sym with valid font/char (ST_ShortHexNumber) is conformant and Word opens it without repair. validate() issues: {detail}"
    );
}

#[test]
fn sym_char_is_four_digit_short_hex() {
    let body = r#"<w:p><w:r><w:sym w:font="Symbol" w:char="003A"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "ECMA-376 §17.18.79 / §17.3.3.30: a four-digit hex char (ST_ShortHexNumber = exactly 4 hex digits) is schema-valid, so Word opens the document without a repair prompt. validate() issues: {detail}"
    );
}

#[test]
fn last_rendered_page_break_preserved_not_regenerated() {
    let body = r#"<w:p><w:r><w:t>This is the end</w:t><w:lastRenderedPageBreak/><w:t xml:space="preserve"> of the page</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    // xmlRegex "(?s)^...exactly-one lastRenderedPageBreak...$" translated to an
    // occurrence-count check (no regex crate): the one authored marker must
    // survive exactly once — not duplicated (the engine does not paginate) and
    // not dropped.
    let count = xml.matches("lastRenderedPageBreak").count();
    assert_eq!(
        count, 1,
        "ECMA-376 §17.3.3.13 / ISO 29500-1 §17.3.3.13: exactly the one authored lastRenderedPageBreak must survive an untouched round-trip; the engine must neither duplicate it (it does not paginate) nor drop it. found {count} occurrence(s). xml: {xml}"
    );
}

#[test]
fn sym_glyph_kept_as_sym_element_not_converted_to_t() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="Courier New" w:hAnsi="Courier New"/></w:rPr><w:sym w:font="Wingdings" w:char="F045"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains("<w:sym"),
        "ECMA-376 §17.3.3.30/§17.3.3.31: the symbol must remain a w:sym element so Word resolves it through sym@font (Wingdings), not the run's rFonts; it must not be transcoded into a w:t literal-text fragment. Expected XML to contain <w:sym. xml: {xml}"
    );
    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "ECMA-376 §17.3.3.30: a well-formed sym inside a run is conformant; Word opens it without repair. validate() issues: {detail}"
    );
}

#[test]
fn sym_pua_char_attr_preserved_not_normalized_on_save() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="Courier New" w:hAnsi="Courier New"/></w:rPr><w:t>before</w:t><w:sym w:font="Wingdings" w:char="F03A"/><w:t>after</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:char="F03A""#),
        "ECMA-376 §17.3.3.30 / ISO/IEC 29500-1 §17.3.3.30: the F000-shifted PUA char form is a valid stored representation; a faithful engine preserves char=\"F03A\" verbatim and must not de-shift it to 003A on save. Expected XML to contain w:char=\"F03A\". xml: {xml}"
    );
    assert!(
        xml.contains(r#"w:font="Wingdings""#),
        "ECMA-376 §17.3.3.30: the sym font attribute names the glyph source font and is opaque content stemma round-trips unchanged. Expected XML to contain w:font=\"Wingdings\". xml: {xml}"
    );
    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "ECMA-376 §17.3.3.30: a well-formed w:sym with valid font + ST_ShortHexNumber char is conformant run content and Word opens it without repair. validate() issues: {detail}"
    );
}

#[test]
fn lastrenderedpagebreak_is_non_semantic_for_accept_reject() {
    let body = r#"<w:p><w:r><w:t>This is the end</w:t><w:lastRenderedPageBreak/><w:t xml:space="preserve"> of the page</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accept_text(&b).trim(),
        "This is the end of the page",
        "ECMA-376 §17.3.3.13/§17.3.3.31: lastRenderedPageBreak is CT_Empty pagination metadata; the accept reading is the two w:t payloads concatenated with no marker-contributed character."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "This is the end of the page",
        "ECMA-376 §17.3.3.13/§17.3.3.31: the marker carries no tracked-change semantics, so the reject reading is identical to the accept reading: the surrounding text verbatim."
    );
}

#[test]
fn sym_direct_unicode_char_form_preserved() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="Arial Black" w:hAnsi="Arial Black"/></w:rPr><w:sym w:font="Wingdings" w:char="0045"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:char="0045""#),
        "ECMA-376 §17.3.3.30: the direct Unicode char form is valid storage; a faithful engine preserves char=\"0045\" verbatim and must not add the F000 PUA offset on save. Expected XML to contain w:char=\"0045\". xml: {xml}"
    );
    assert!(
        !xml.contains(r#"w:char="F045""#),
        "ECMA-376 §17.3.3.30: shifting a direct-form char into the PUA on save would change the font-matching intent the producer encoded; stemma must not rewrite 0045 to F045. Expected XML to omit w:char=\"F045\". xml: {xml}"
    );
    let (ok, detail) = opens_clean(&b);
    assert!(
        ok,
        "ECMA-376 §17.3.3.30: a w:sym with a direct ST_ShortHexNumber char and a valid font is conformant run content that Word opens without repair. validate() issues: {detail}"
    );
}

#[test]
fn sym_char_f000_pua_offset_preserved_verbatim_on_serialize() {
    let body = r#"<w:p><w:r><w:sym w:font="Symbol" w:char="F0B7"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:char="F0B7""#),
        "ECMA-376 §17.3.3.30 / ISO 29500-1 §17.3.3.30: the PUA-shifted char value is intentional stored markup; an unedited sym must serialize its char attribute verbatim (passthrough preservation), not normalize the F000 offset away. Expected XML to contain w:char=\"F0B7\". xml: {xml}"
    );
    assert!(
        !xml.contains(r#"w:char="00B7""#),
        "ECMA-376 §17.3.3.30 / ISO 29500-1 §17.3.3.30: collapsing F0B7 to 00B7 would discard the legacy 'suppress font matching' PUA signal; the engine must not perform this normalization on a verbatim-preserved sym. Expected XML to omit w:char=\"00B7\". xml: {xml}"
    );
}

#[test]
fn sym_font_attribute_preserved_independent_of_run_rfonts() {
    let body = r#"<w:p><w:r><w:rPr><w:rFonts w:ascii="Courier New" w:hAnsi="Courier New"/></w:rPr><w:t>This is a symbol character:</w:t><w:sym w:font="Wingdings" w:char="F03A"/></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    let xml = reserialize(&b);
    assert!(
        xml.contains(r#"w:font="Wingdings""#),
        "ECMA-376 §17.3.3.30 / ISO 29500-1 §17.3.3.30: the sym font attribute is authoritative for the glyph and independent of the run rFonts; an unedited sym must serialize its font attribute verbatim. Expected XML to contain w:font=\"Wingdings\". xml: {xml}"
    );
    // xmlRegex "<w:sym[^>]*w:font=\"Wingdings\"[^>]*w:char=\"F03A\"" translated
    // (no regex crate): require a single w:sym element start tag whose substring
    // up to its '>' carries both font=Wingdings and char=F03A, with font before
    // char (the authored attribute order).
    let sym_tag = xml
        .split_once("<w:sym")
        .and_then(|(_, rest)| rest.split_once('>').map(|(tag, _)| tag));
    let sym_tag = sym_tag.expect("a <w:sym ...> element must be present in serialized XML");
    let font_pos = sym_tag.find(r#"w:font="Wingdings""#);
    let char_pos = sym_tag.find(r#"w:char="F03A""#);
    assert!(
        font_pos.is_some() && char_pos.is_some() && font_pos < char_pos,
        "ECMA-376 §17.3.3.30: both sym attributes (font + char) are required state for the glyph and must be preserved together on the sym element (font=Wingdings before char=F03A). sym tag was <w:sym{sym_tag}>. full xml: {xml}"
    );
}

#[test]
fn lastrenderedpagebreak_is_non_semantic_no_text_no_separator() {
    let body = r#"<w:p><w:r><w:t>This is the end</w:t><w:lastRenderedPageBreak/><w:t xml:space="preserve"> of the page</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accept_text(&b).trim(),
        "This is the end of the page",
        "ECMA-376 §17.3.3.13 / ISO 29500-1 §17.3.3.13 / §17.3.3.31: the page-break marker is empty pagination metadata; accepted text is the two w:t fragments concatenated with the single space supplied by the preserved payload, no marker glyph or separator."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "This is the end of the page",
        "ECMA-376 §17.3.3.13 / ISO 29500-1 §17.3.3.13 / §17.3.3.31: the marker carries no tracked-change semantics; reject-all leaves the untracked run intact, so rejected text equals accepted text."
    );
}

