#[test]
fn sym_surfaces_as_one_object_replacement_anchor_in_accept_and_reject() {
    // w:sym is a font-specific symbol glyph (§17.3.3.30/§17.3.3.31): it carries no
    // Unicode plain-text equivalent, so it is a "true no-text object" anchor. Per
    // stemma's documented read-projection contract (src/view.rs ~750-761), every
    // such opaque anchor contributes EXACTLY ONE U+FFFC (OBJECT REPLACEMENT
    // CHARACTER) — never zero (dropping it would break the one-U+FFFC-per-anchor
    // countability invariant) and never a synthesized glyph. So the symbol reads
    // as a single U+FFFC between the two text fragments. (Asserting "ABCD" with
    // the symbol dropped contradicts that contract; the spec does not mandate a
    // plain-text projection that erases the glyph.)
    let body = r#"<w:p><w:r><w:t>AB</w:t><w:sym w:font="Wingdings" w:char="F0E8"/><w:t>CD</w:t></w:r></w:p><w:sectPr/>"#;
    let b = make_docx(body, &[]);
    assert_eq!(
        accept_text(&b).trim(),
        "AB\u{FFFC}CD",
        "§17.3.3.30/§17.3.3.31 + stemma read contract (view.rs): sym is a no-text glyph anchor; the surrounding t fragments concatenate with exactly one U+FFFC for the symbol."
    );
    assert_eq!(
        reject_text(&b).trim(),
        "AB\u{FFFC}CD",
        "§17.3.3.30/§17.3.3.31: sym is non-tracked content unaffected by reject, so reject reads identically to accept (one U+FFFC for the symbol)."
    );
}
